    class SphereGeometry extends BufferGeometry {
        constructor(r=1, ws=32, hs=16) {
            super();
            const pos=[], norm=[], uv=[], idx=[];
            for (let y=0; y<=hs; y++) {
                const v = y/hs, phi = v*Math.PI;
                for (let x=0; x<=ws; x++) {
                    const u = x/ws, theta = u*Math.PI*2;
                    const px = -r*Math.cos(theta)*Math.sin(phi);
                    const py = r*Math.cos(phi);
                    const pz = r*Math.sin(theta)*Math.sin(phi);
                    pos.push(px,py,pz);
                    const n = new Vec3(px,py,pz).normalize();
                    norm.push(n.x,n.y,n.z);
                    uv.push(u, 1-v);
                }
            }
            for (let y=0; y<hs; y++) {
                for (let x=0; x<ws; x++) {
                    const a = y*(ws+1)+x, b = a+ws+1;
                    idx.push(a,b,a+1, b,b+1,a+1);
                }
            }
            this.setAttribute('position', pos, 3);
            this.setAttribute('normal', norm, 3);
            this.setAttribute('uv', uv, 2);
            this.setIndex(idx);
        }
    }
    
    class PlaneGeometry extends BufferGeometry {
        constructor(w=1, h=1, ws=1, hs=1) {
            super();
            const hw=w/2, hh=h/2;
            const pos=[], norm=[], uv=[], idx=[];
            for (let y=0; y<=hs; y++) {
                for (let x=0; x<=ws; x++) {
                    const px = (x/ws)*w - hw;
                    const py = (y/hs)*h - hh;
                    pos.push(px, py, 0);
                    norm.push(0, 0, 1);
                    uv.push(x/ws, y/hs);
                }
            }
            for (let y=0; y<hs; y++) {
                for (let x=0; x<ws; x++) {
                    const a = y*(ws+1)+x, b = a+ws+1;
                    idx.push(a,b,a+1, b,b+1,a+1);
                }
            }
            this.setAttribute('position', pos, 3);
            this.setAttribute('normal', norm, 3);
            this.setAttribute('uv', uv, 2);
            this.setIndex(idx);
        }
    }
    
    class CylinderGeometry extends BufferGeometry {
        constructor(radiusTop=1, radiusBottom=1, height=1, radialSegments=32, heightSegments=1, openEnded=false) {
            super();
            const pos=[], norm=[], uv=[], idx=[];
            const halfHeight = height/2;
            let index = 0;
            for (let y=0; y<=heightSegments; y++) {
                const v = y/heightSegments;
                const radius = v*(radiusBottom-radiusTop) + radiusTop;
                for (let x=0; x<=radialSegments; x++) {
                    const u = x/radialSegments;
                    const theta = u*Math.PI*2;
                    const px = radius*Math.cos(theta);
                    const py = -v*height + halfHeight;
                    const pz = radius*Math.sin(theta);
                    pos.push(px, py, pz);
                    const slope = (radiusBottom-radiusTop)/height;
                    const n = new Vec3(Math.cos(theta), slope, Math.sin(theta)).normalize();
                    norm.push(n.x, n.y, n.z);
                    uv.push(u, 1-v);
                    index++;
                }
            }
            for (let y=0; y<heightSegments; y++) {
                for (let x=0; x<radialSegments; x++) {
                    const a = y*(radialSegments+1)+x;
                    const b = a+radialSegments+1;
                    idx.push(a,b,a+1, b,b+1,a+1);
                }
            }
            this.setAttribute('position', pos, 3);
            this.setAttribute('normal', norm, 3);
            this.setAttribute('uv', uv, 2);
            this.setIndex(idx);
        }
    }
    
    class TorusGeometry extends BufferGeometry {
        constructor(radius=1, tube=0.4, radialSegments=12, tubularSegments=48) {
            super();
            const pos=[], norm=[], uv=[], idx=[];
            for (let j=0; j<=radialSegments; j++) {
                for (let i=0; i<=tubularSegments; i++) {
                    const u = i/tubularSegments*Math.PI*2;
                    const v = j/radialSegments*Math.PI*2;
                    const px = (radius + tube*Math.cos(v))*Math.cos(u);
                    const py = (radius + tube*Math.cos(v))*Math.sin(u);
                    const pz = tube*Math.sin(v);
                    pos.push(px, py, pz);
                    const cx = radius*Math.cos(u);
                    const cy = radius*Math.sin(u);
                    const n = new Vec3(px-cx, py-cy, pz).normalize();
                    norm.push(n.x, n.y, n.z);
                    uv.push(i/tubularSegments, j/radialSegments);
                }
            }
            for (let j=1; j<=radialSegments; j++) {
                for (let i=1; i<=tubularSegments; i++) {
                    const a = (tubularSegments+1)*j + i - 1;
                    const b = (tubularSegments+1)*(j-1) + i - 1;
                    const c = (tubularSegments+1)*(j-1) + i;
                    const d = (tubularSegments+1)*j + i;
                    idx.push(a,b,d, b,c,d);
                }
            }
            this.setAttribute('position', pos, 3);
            this.setAttribute('normal', norm, 3);
            this.setAttribute('uv', uv, 2);
            this.setIndex(idx);
        }
    }
    
